  accountantQuestions: [
    { q: "Based on my planned absence + trustee structure, are we at risk of breaching the CM&C test?", why: "This is the single most common failure point. A structural review before departure is materially cheaper than post-breach remediation." },
    { q: "Should we restructure to a corporate trustee, and if so, which director roles need to be AU-resident?", why: "Corporate trusteeship is often the cleanest shield but only effective with genuine AU-director control." },
    { q: "Does the active member test still pass if [scenario] plays out?", why: "Often the forgotten test — becomes critical if all active members move overseas." },
    { q: "What documentation protocol should we adopt for decisions made during absence?", why: "Minutes + evidence trail supports the CM&C-in-AU position under any future ATO review." },
    { q: "What are the alternatives — APRA fund roll-over, pension phase, fund wind-up?", why: "For some situations, closing or rolling over the SMSF is cheaper than maintaining it in a high-risk structure." },
  ],
  crosslink: { title: "Confirm your Australian tax residency first", body: "SMSF residency and your personal AU tax residency interact but are different tests. Before analysing CM&C risk, confirm your personal residency position using the 183-Day Rule Reality Check — then return here for the SMSF-specific risk assessment.", url: "/nomad/check/183-day-rule", label: "Residency Reality Check →" },
  lawBarSummary: "Australian SMSF Residency Kill-Switch — SIS Act 1993 s 10(1) defines 'Australian superannuation fund' via three tests: (1) establishment in Australia or assets in Australia; (2) central management and control (CM&C) ordinarily in Australia; (3) active member test — 50%+ of active member balances from AU residents (or no active members). Failure on any test = non-complying fund under ITAA 1997 s 295-320: 'low tax component' (approximately full fund value less undeducted contributions) taxed at 45% in year of change PLUS ongoing earnings taxed at 45% (vs complying 15%). ATO accepts temporary absence up to ~2 years with return intent. Corporate trustee with AU-resident director who genuinely exercises control is standard structural safeguard. Remediation via ATO approval — not automatic.",
  lawBarBadges: ["ATO", "SIS Act s 10(1)", "ITAA 1997 s 295-320", "45% Non-Complying Tax", "Central Management and Control", "2-Year Temporary Absence"],
